const LOGIN_JS = "const form = document.querySelector('#loginForm');\nconst usernameInput = document.querySelector('#loginUsername');\nconst passwordInput = document.querySelector('#loginPassword');\nconst submitButton = document.querySelector('#loginButton');\nconst errorBox = document.querySelector('#loginError');\nconst toggleButton = document.querySelector('#togglePasswordButton');\n\nfunction showError(message) {\n  errorBox.textContent = message;\n  errorBox.classList.remove('hidden');\n}\n\nfunction clearError() {\n  errorBox.textContent = '';\n  errorBox.classList.remove('success');\n  errorBox.classList.add('hidden');\n}\n\nfunction setBusy(busy) {\n  submitButton.disabled = busy;\n  usernameInput.disabled = busy;\n  passwordInput.disabled = busy;\n  submitButton.textContent = busy ? '正在登录…' : '登录管理后台';\n}\n\ntoggleButton.addEventListener('click', () => {\n  const showing = passwordInput.type === 'text';\n  passwordInput.type = showing ? 'password' : 'text';\n  toggleButton.textContent = showing ? '显示' : '隐藏';\n  toggleButton.setAttribute('aria-label', showing ? '显示密码' : '隐藏密码');\n  passwordInput.focus({ preventScroll: true });\n});\n\nform.addEventListener('submit', async (event) => {\n  event.preventDefault();\n  clearError();\n  const username = usernameInput.value.trim();\n  const password = passwordInput.value;\n  if (!username || !password) {\n    showError('请输入管理账号和登录密码。');\n    return;\n  }\n\n  setBusy(true);\n  try {\n    const response = await fetch('/api/auth/login', {\n      method: 'POST',\n      credentials: 'same-origin',\n      headers: { 'Content-Type': 'application/json', Accept: 'application/json' },\n      body: JSON.stringify({ username, password })\n    });\n    let payload = {};\n    try { payload = await response.json(); } catch {}\n    if (!response.ok) throw new Error(payload.error || `登录失败（${response.status}）`);\n    window.location.replace('/');\n  } catch (error) {\n    showError(error.message || '登录失败，请稍后再试。');\n    setBusy(false);\n    passwordInput.select();\n  }\n});\n\nconst params = new URLSearchParams(window.location.search);\nif (params.get('expired') === '1') showError('登录状态已失效，请重新登录。');\nif (params.get('logout') === '1') { showError('你已安全退出登录。'); errorBox.classList.add('success'); }\n\nrequestAnimationFrame(() => usernameInput.focus({ preventScroll: true }));\n";
